import React from 'react';
import { FiTrendingUp, FiDollarSign } from 'react-icons/fi';
import { generateDynamicData } from '../../utils/dynamicData';

interface Props { skillId?: string; }

const ROIEstimation: React.FC<Props> = ({ skillId }) => {
  const data = generateDynamicData(skillId);

  return (
    <div className="space-y-6 animate-fadeIn">
      <div className="bg-white p-8 rounded-2xl shadow-sm border border-gray-200">
        <h3 className="text-2xl font-bold text-gray-900 mb-6 flex items-center gap-2">
          <FiTrendingUp className="text-green-500" /> Learning ROI for {data.skill}
        </h3>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-8">
          <div className="p-6 bg-green-50 rounded-2xl border border-green-100 flex flex-col items-center justify-center text-center">
            <FiDollarSign className="text-green-500 mb-2" size={32} />
            <div className="text-4xl font-black text-green-600 mb-1">+{data.roi.salaryIncrease}%</div>
            <div className="text-gray-600 font-medium">Estimated Salary Bump</div>
          </div>

          <div className="p-6 bg-blue-50 rounded-2xl border border-blue-100 flex flex-col items-center justify-center text-center">
            <div className="text-4xl font-black text-blue-600 mb-1">{data.roi.paybackPeriod} mo</div>
            <div className="text-gray-600 font-medium">Time to Payback</div>
          </div>
        </div>

        <div className="p-5 bg-gray-50 rounded-xl border border-gray-200">
          <h4 className="font-bold text-gray-900 mb-2">Market Impact</h4>
          <p className="text-gray-600 text-sm">
            Acquiring this skill opens up approximately <strong className="text-blue-600">{data.roi.newOpportunities}+ new job roles</strong> that match your updated profile, primarily in remote and hybrid environments.
          </p>
        </div>
      </div>
    </div>
  );
};

export default ROIEstimation;
